import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';

const tags = [
  '⚙️ Mechanical', '⚡ Electrical', '📡 IoT',
  '📟 Embedded', '🤖 Robotics', '💻 Software',
  '🔩 Hardware', '🧊 3D Design',
];

/* ── Gear geometry ── */
function buildGear(teeth, innerR, outerR, toothW = 0.45, depth = 0.22) {
  const shape = new THREE.Shape();
  const total = teeth * 2;
  for (let i = 0; i < total; i++) {
    const a0 = (i / total) * Math.PI * 2;
    const a1 = ((i + toothW) / total) * Math.PI * 2;
    const a2 = ((i + toothW + 0.05) / total) * Math.PI * 2;
    const a3 = ((i + 1) / total) * Math.PI * 2;
    const r0 = i % 2 === 0 ? outerR : innerR;
    const r1 = i % 2 === 0 ? outerR : innerR;
    const r2 = i % 2 === 0 ? innerR : outerR;
    const r3 = i % 2 === 0 ? innerR : outerR;
    const fn = i === 0 ? 'moveTo' : 'lineTo';
    shape[fn](Math.cos(a0) * r0, Math.sin(a0) * r0);
    shape.lineTo(Math.cos(a1) * r1, Math.sin(a1) * r1);
    shape.lineTo(Math.cos(a2) * r2, Math.sin(a2) * r2);
    shape.lineTo(Math.cos(a3) * r3, Math.sin(a3) * r3);
  }
  shape.closePath();
  const hole = new THREE.Path();
  hole.absarc(0, 0, innerR * 0.42, 0, Math.PI * 2, true);
  shape.holes.push(hole);
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth, bevelEnabled: true,
    bevelThickness: 0.02, bevelSize: 0.015, bevelSegments: 3,
  });
  geo.center();
  return geo;
}

function buildHub(r, depth) {
  return new THREE.CylinderGeometry(r, r, depth + 0.06, 32);
}

/* ── PCB board geometry ── */
function buildPCB(scene, matCyan, matPurple, matAccent) {
  const group = new THREE.Group();

  // Main board
  const boardGeo = new THREE.BoxGeometry(5.5, 3.2, 0.12);
  const boardMat = new THREE.MeshStandardMaterial({
    color: 0x001a0d, emissive: 0x002208, emissiveIntensity: 0.6,
    metalness: 0.4, roughness: 0.7,
  });
  const board = new THREE.Mesh(boardGeo, boardMat);
  group.add(board);

  // Board edge wireframe
  const edgeGeo = new THREE.EdgesGeometry(boardGeo);
  const edgeMat = new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.5 });
  group.add(new THREE.LineSegments(edgeGeo, edgeMat));

  // IC chips on board
  const chipMat = new THREE.MeshStandardMaterial({
    color: 0x0a0a0a, emissive: 0x001122, emissiveIntensity: 0.4,
    metalness: 0.8, roughness: 0.3,
  });
  const chips = [
    { x: -1.6, y:  0.5, w: 0.9, h: 0.9 },
    { x:  0.2, y:  0.5, w: 1.1, h: 0.7 },
    { x:  1.6, y: -0.4, w: 0.7, h: 0.7 },
    { x: -0.5, y: -0.6, w: 0.6, h: 0.5 },
    { x:  1.8, y:  0.6, w: 0.5, h: 0.4 },
    { x: -1.8, y: -0.5, w: 0.5, h: 0.6 },
  ];
  chips.forEach(c => {
    const cGeo = new THREE.BoxGeometry(c.w, c.h, 0.09);
    const chip = new THREE.Mesh(cGeo, chipMat);
    chip.position.set(c.x, c.y, 0.11);
    group.add(chip);
    // Chip edge
    const cEdge = new THREE.LineSegments(
      new THREE.EdgesGeometry(cGeo),
      new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.7 })
    );
    cEdge.position.copy(chip.position);
    group.add(cEdge);
    // Tiny pin dots
    for (let p = 0; p < 4; p++) {
      const pin = new THREE.Mesh(
        new THREE.BoxGeometry(0.06, 0.04, 0.03),
        new THREE.MeshStandardMaterial({ color: 0xccaa00, emissive: 0x886600, emissiveIntensity: 0.8, metalness: 1 })
      );
      pin.position.set(c.x - c.w / 2 - 0.05, c.y - c.h / 4 + p * (c.h / 4), 0.085);
      group.add(pin);
    }
  });

  // Trace lines (circuit paths)
  const traceMat = new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.35 });
  const tracePurple = new THREE.LineBasicMaterial({ color: 0xbf00ff, transparent: true, opacity: 0.28 });

  const traces = [
    [[-2.5, 0.5], [-1.6, 0.5]],
    [[-1.15, 0.5], [0.2, 0.5]],
    [[0.75, 0.5], [1.6, 0.5]],
    [[0.2, 0.15], [0.2, -0.35]],
    [[-0.5, -0.35], [1.6, -0.35]],
    [[-1.6, 0.05], [-1.6, -0.5]],
    [[-1.6, -0.5], [-0.5, -0.5]],
    [[1.6, -0.05], [1.6, -0.35]],
    [[2.0, 0.6], [2.5, 0.6]],
    [[-2.0, -0.5], [-2.5, -0.5]],
    [[0.5, -0.6], [0.5, -1.2]],
    [[-0.8, 0.5], [-0.8, 1.2]],
  ];

  traces.forEach((pts, i) => {
    const points = pts.map(([x, y]) => new THREE.Vector3(x, y, 0.14));
    const geo = new THREE.BufferGeometry().setFromPoints(points);
    group.add(new THREE.Line(geo, i % 2 === 0 ? traceMat : tracePurple));
  });

  // Capacitors (small cylinders)
  const capMat = new THREE.MeshStandardMaterial({
    color: 0x002244, emissive: 0x0044aa, emissiveIntensity: 0.6, metalness: 0.7, roughness: 0.3,
  });
  [[-0.8, 1.0], [0.5, -1.0], [2.1, 0.0], [-2.1, 0.2]].forEach(([x, y]) => {
    const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.1, 0.1, 0.22, 12), capMat);
    cap.rotation.x = Math.PI / 2;
    cap.position.set(x, y, 0.17);
    group.add(cap);
  });

  // Corner mounting holes
  [[-2.4, 1.35], [2.4, 1.35], [-2.4, -1.35], [2.4, -1.35]].forEach(([x, y]) => {
    const ring = new THREE.Mesh(
      new THREE.TorusGeometry(0.12, 0.025, 8, 24),
      new THREE.MeshStandardMaterial({ color: 0x888800, emissive: 0x444400, metalness: 1 })
    );
    ring.position.set(x, y, 0.13);
    group.add(ring);
  });

  return group;
}

export default function Home({ onNavigate }) {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const W = mount.clientWidth;
    const H = mount.clientHeight;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    const scene  = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(52, W / H, 0.1, 100);
    camera.position.set(0, 0, 7.5);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping   = true;
    controls.dampingFactor   = 0.07;
    controls.enableZoom      = true;
    controls.zoomSpeed       = 0.5;
    controls.minDistance     = 4;
    controls.maxDistance     = 13;
    controls.autoRotate      = true;
    controls.autoRotateSpeed = 0.5;
    controls.addEventListener('start', () => { controls.autoRotate = false; });

    // Lighting
    scene.add(new THREE.AmbientLight(0xffffff, 0.2));
    const dir1 = new THREE.DirectionalLight(0x00f5ff, 2.0);
    dir1.position.set(5, 7, 6);
    scene.add(dir1);
    const dir2 = new THREE.DirectionalLight(0xbf00ff, 1.4);
    dir2.position.set(-5, -4, -3);
    scene.add(dir2);
    const dir3 = new THREE.DirectionalLight(0x00f5ff, 0.6);
    dir3.position.set(0, -6, 3);
    scene.add(dir3);

    // Materials
    const matCyan = new THREE.MeshStandardMaterial({
      color: 0x003344, emissive: 0x00b8cc, emissiveIntensity: 0.4,
      metalness: 0.92, roughness: 0.2,
    });
    const matPurple = new THREE.MeshStandardMaterial({
      color: 0x1a0033, emissive: 0x9900dd, emissiveIntensity: 0.45,
      metalness: 0.92, roughness: 0.18,
    });
    const matAccent = new THREE.MeshStandardMaterial({
      color: 0x002233, emissive: 0x004466, emissiveIntensity: 0.5,
      metalness: 0.95, roughness: 0.12,
    });

    /* ── GEAR GROUP (upper area) ── */
    const gearGroup = new THREE.Group();
    gearGroup.position.y = 2.2;
    scene.add(gearGroup);

    const bigGear = new THREE.Mesh(buildGear(16, 0.82, 1.22, 0.42, 0.26), matCyan);
    bigGear.position.set(-1.0, 0, 0);
    gearGroup.add(bigGear);
    const bigHub = new THREE.Mesh(buildHub(0.32, 0.26), matAccent);
    bigHub.rotation.x = Math.PI / 2;
    bigHub.position.copy(bigGear.position);
    gearGroup.add(bigHub);

    const medOuter = 0.78;
    const medGear = new THREE.Mesh(buildGear(10, 0.52, medOuter, 0.42, 0.24), matPurple);
    medGear.position.set(-1.0 + 1.22 + medOuter - 0.06, 0, 0);
    gearGroup.add(medGear);
    const medHub = new THREE.Mesh(buildHub(0.22, 0.24), matAccent);
    medHub.rotation.x = Math.PI / 2;
    medHub.position.copy(medGear.position);
    gearGroup.add(medHub);

    const smOuter = 0.50;
    const smGear = new THREE.Mesh(buildGear(6, 0.34, smOuter, 0.42, 0.20), matCyan);
    smGear.position.set(medGear.position.x, medGear.position.y + medOuter + smOuter - 0.05, 0.05);
    gearGroup.add(smGear);
    const smHub = new THREE.Mesh(buildHub(0.14, 0.20), matAccent);
    smHub.rotation.x = Math.PI / 2;
    smHub.position.copy(smGear.position);
    gearGroup.add(smHub);

    const tinyOuter = 0.60;
    const tinyGear = new THREE.Mesh(buildGear(8, 0.40, tinyOuter, 0.42, 0.18), matPurple);
    tinyGear.position.set(bigGear.position.x - 0.1, bigGear.position.y - 1.22 - tinyOuter + 0.05, -0.05);
    gearGroup.add(tinyGear);
    const tinyHub = new THREE.Mesh(buildHub(0.16, 0.18), matAccent);
    tinyHub.rotation.x = Math.PI / 2;
    tinyHub.position.copy(tinyGear.position);
    gearGroup.add(tinyHub);

    /* ── PCB GROUP (lower area) ── */
    const pcbGroup = buildPCB(scene, matCyan, matPurple, matAccent);
    pcbGroup.position.y = -2.0;
    pcbGroup.rotation.x = 0.22;
    scene.add(pcbGroup);

    /* ── Divider line between gear and PCB ── */
    const divPoints = [
      new THREE.Vector3(-3, 0.4, 0),
      new THREE.Vector3( 3, 0.4, 0),
    ];
    const divGeo = new THREE.BufferGeometry().setFromPoints(divPoints);
    const divLine = new THREE.Line(divGeo, new THREE.LineBasicMaterial({
      color: 0x00f5ff, transparent: true, opacity: 0.15,
    }));
    scene.add(divLine);

    /* ── Floating particles ── */
    const pCount = 120;
    const pPos = new Float32Array(pCount * 3);
    for (let i = 0; i < pCount; i++) {
      pPos[i*3]   = (Math.random() - 0.5) * 7;
      pPos[i*3+1] = (Math.random() - 0.5) * 9;
      pPos[i*3+2] = (Math.random() - 0.5) * 4;
    }
    const pGeo = new THREE.BufferGeometry();
    pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
    const particles = new THREE.Points(pGeo, new THREE.PointsMaterial({
      color: 0x00f5ff, size: 0.022, transparent: true, opacity: 0.45,
    }));
    scene.add(particles);

    /* ── Gear speeds ── */
    const bigSpeed  =  0.30;
    const medSpeed  = -(16/10) * bigSpeed;
    const smSpeed   = -(10/ 6) * medSpeed;
    const tinySpeed = -(16/ 8) * bigSpeed;

    /* ── Animate ── */
    let frameId;
    const clock = new THREE.Clock();
    const animate = () => {
      frameId = requestAnimationFrame(animate);
      const dt = clock.getDelta();
      const t  = clock.elapsedTime;

      bigGear.rotation.z  += bigSpeed  * dt;
      medGear.rotation.z  += medSpeed  * dt;
      smGear.rotation.z   += smSpeed   * dt;
      tinyGear.rotation.z += tinySpeed * dt;

      // Subtle tilt oscillation
      gearGroup.rotation.x = Math.sin(t * 0.2) * 0.1;
      gearGroup.rotation.y = Math.sin(t * 0.15) * 0.07;

      // PCB gentle float
      pcbGroup.position.y = -2.0 + Math.sin(t * 0.5) * 0.06;
      pcbGroup.rotation.z = Math.sin(t * 0.3) * 0.015;

      particles.rotation.y += 0.0001;

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const onResize = () => {
      const nw = mount.clientWidth;
      const nh = mount.clientHeight;
      camera.aspect = nw / nh;
      camera.updateProjectionMatrix();
      renderer.setSize(nw, nh);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(frameId);
      controls.dispose();
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, []);

  return (
    <section className="home-section">

      {/* ── Left column ── */}
      <div className="hero-content">
        <div className="hero-label">// Computer Engineering · IPB University · Bogor</div>

        <h1 className="hero-title">
          Engineer at<br />
          <span className="hero-title-gradient">Every Layer.</span><br />
          Hardware to Code.
        </h1>

        <p className="hero-sub">
          Mechanical · Electrical · IoT · Embedded · Robotics · Software · 3D Design
        </p>

        <p className="hero-desc">
          Naufal Auzan — final-year Computer Engineering student at IPB University
          yang membangun sistem dari komponen fisik hingga aplikasi digital.
          Dari chassis UGV berbasis AI hingga sistem IoT real-time.
        </p>

        <div className="hero-tags">
          {tags.map(t => <span key={t} className="tag">{t}</span>)}
        </div>

        <div className="hero-cta">
          <button className="btn-primary" onClick={() => onNavigate('projects')}>
            View Projects
          </button>
          <button className="btn-outline" onClick={() => onNavigate('contact')}>
            Get In Touch
          </button>
        </div>

        {/* Terminal */}
        <div className="hero-terminal">
          <div className="terminal-bar">
            <div className="tb tb-r" />
            <div className="tb tb-y" />
            <div className="tb tb-g" />
            <span className="terminal-title">engineer.sh</span>
          </div>
          <div className="terminal-body">
            <div><span className="t-prompt">$ </span><span className="t-cmd">whoami</span></div>
            <span className="t-out">polymath_engineer@system:~</span>
            <br />
            <div><span className="t-prompt">$ </span><span className="t-cmd">cat skills.json</span></div>
            <span className="t-out">{'{'}</span>
            <span className="t-out">&nbsp;&nbsp;"mechanical": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"electrical": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"IoT": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"robotics": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"embedded": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"3d_design": <span className="t-val">true</span></span>
            <span className="t-out">{'}'}</span>
            <br />
            <div><span className="t-prompt">$ </span><span className="t-cmd">status</span></div>
            <span className="t-out">→ <span className="t-val">READY TO BUILD</span> <span className="t-cursor" /></span>
          </div>
        </div>
      </div>

      {/* ── Right column: full-height 3D ── */}
      <div className="hero-3d-wrapper">
        <div className="hero-3d" ref={mountRef} />
        {/* Labels */}
        <div className="model-label model-label-top">⚙ GEAR MECHANISM</div>
        <div className="model-label model-label-bottom">◈ PCB / CIRCUIT BOARD</div>
        <div className="drag-hint">⟳ drag · scroll to zoom</div>
      </div>

    </section>
  );
}
